chrome.runtime.onInstalled.addListener(e=>{e.reason==="install"?console.log("[Figma TodoList] Extension installed!"):e.reason==="update"&&console.log("[Figma TodoList] Extension updated!")});chrome.runtime.onMessage.addListener((e,r,o)=>{switch(console.log("[Figma TodoList] Message received:",e),e.type){case"GET_STORAGE":return chrome.storage.local.get(e.key,t=>{o(t[e.key])}),!0;case"SET_STORAGE":return chrome.storage.local.set({[e.key]:e.value},()=>{o({success:!0})}),!0;case"GET_ALL_TODOS":return chrome.storage.local.get(null,t=>{o(t)}),!0;default:o({error:"Unknown message type"})}});chrome.tabs.onUpdated.addListener((e,r,o)=>{var t;r.url&&((t=o.url)!=null&&t.includes("figma.com/design"))&&(console.log("[Figma TodoList] Navigated to Figma design:",o.url),chrome.tabs.sendMessage(e,{type:"FIGMA_NAVIGATION"}).catch(()=>{}))});chrome.action.onClicked.addListener(e=>{var r;(r=e.url)!=null&&r.includes("figma.com")&&chrome.tabs.sendMessage(e.id,{type:"TOGGLE_TODO_LIST"}).catch(()=>{console.warn("[Figma TodoList] Could not toggle, content script not ready")})});console.log("[Figma TodoList] Background service worker started");
